 19	import {
 20	  Button,
 21	  ButtonVariant,
 22	  Form,
 23	  FormGroup,
 24	  Modal,
 25	  ModalVariant,
 26	} from '@patternfly/react-core';
 27	
 28	type AddLunGroupModalProps = {
 29	  isOpen: boolean;
 30	  closeModal: () => void;
 31	  onSubmit: () => void;
 32	  inProgress: boolean;
 33	  error: string;
 34	};
 35	
 36	const AddLunGroupModal: React.FC<AddLunGroupModalProps> = ({
 37	  isOpen,
 38	  closeModal: onClose,
 39	}) => {
 40	  const { t } = useCustomTranslation();
 41	  const [selectedLUNs, setSelectedLUNs] = React.useState<Set<string>>(
 42	    new Set()
 43	  );
 44	  const [inProgress, setInProgress] = React.useState(false);
 45	  const [error, setError] = React.useState<Error>(undefined);
 46	  const { deviceFinderLoading, sharedDevices } = useDeviceFinder();
 47	
 48	  const [disks] = useK8sWatchResource<LocalDiskKind[]>({
 49	    groupVersionKind: {
 50	      group: LocalDiskModel.apiGroup,
 51	      version: LocalDiskModel.apiVersion,
 52	      kind: LocalDiskModel.kind,
 53	    },
 54	    isList: true,
 55	  });
 56	
 57	  const existingFileSystemNames = useExistingFileSystemNames();
 58	
 59	  const { fieldRequirements, control, watch } = useSANSystemFormValidation(
 60	    existingFileSystemNames
 61	  );
 62	
 63	  // Watch form field
 64	  const lunGroupName = watch('lunGroupName');
 65	
 66	  const filteredDevices = React.useMemo(
 67	    () => filterUsedDiscoveredDevices(sharedDevices, disks),
 68	    [sharedDevices, disks]
 69	  );
 70	
 71	  const createLunGroup = async () => {
 72	    setInProgress(true);
 73	    setError(undefined);
 74	    const selectedLUNsWWNArray = Array.from(selectedLUNs);
 75	    const selectedLUNsData: DiscoveredDevice[] = filteredDevices.filter(
 76	      (device) => selectedLUNsWWNArray.includes(device.WWN)
 77	    );
 78	    try {
 79	      const localDisks = await createLocalDisks(selectedLUNsData, t);
 80	      const fileSystem = await createLocalFileSystem(
 81	        lunGroupName,
 82	        localDisks,
 83	        t
 84	      );
 85	      await createStorageClass(fileSystem, t);
 86	      setInProgress(false);
 87	      onClose();
 88	    } catch (err) {
 89	      setError(err);
 90	      setInProgress(false);
 91	    }
 92	  };
 93	
 94	  return (
 95	    <Modal
 96	      title={t('Create LUN group')}
 97	      description={t(
 98	        'Enter a name for the group and select one or more of the available LUNs.'
 99	      )}
100	      isOpen={isOpen}
101	      onClose={onClose}
102	      variant={ModalVariant.medium}
103	      actions={[
104	        <ButtonBar
105	          inProgress={inProgress}
106	          errorMessage={error?.message || JSON.stringify(error)}
107	        >
108	          <span>
109	            <Button
110	              variant={ButtonVariant.primary}
111	              onClick={createLunGroup}
112	              isDisabled={
113	                inProgress || _.isEmpty(selectedLUNs) || !lunGroupName
114	              }
115	              isLoading={inProgress}
116	            >
117	              {t('Connect and create')}
118	            </Button>
119	            <Button variant={ButtonVariant.link} onClick={onClose}>
120	              {t('Cancel')}
121	            </Button>
122	          </span>
123	        </ButtonBar>,
124	      ]}
125	    >
126	      <Form>
127	        <TextInputWithFieldRequirements
128	          control={control}
129	          fieldRequirements={fieldRequirements.lunGroupName}
130	          popoverProps={{
131	            headerContent: t('LUN group name requirements'),
132	            footerContent: `${t('Example')}: lun-group-a`,
133	          }}
134	          formGroupProps={{
135	            label: t('LUN group name'),
136	            fieldId: 'lun-group-name',
137	            isRequired: true,
138	          }}
139	          textInputProps={{
140	            id: 'lunGroupName',
141	            name: 'lunGroupName',
142	            type: 'text',
143	            'data-test': 'lun-group-name',
144	          }}
145	        />
146	        <FormGroup label={t('Disks')} fieldId="disks">
147	          <LUNsTable
148	            luns={filteredDevices}
149	            selectedLUNs={selectedLUNs}
150	            onLUNSelect={setSelectedLUNs}
151	            loaded={!deviceFinderLoading}
152	          />
153	        </FormGroup>
154	      </Form>
155	    </Modal>
156	  );
157	};
158	
159	export default AddLunGroupModal;

